// Get data from previous nodes
const confidenceData = $('Confidence Evaluator').item.json;
const configData = $('Workflow Configuration').first().json;
const cheapModelData = $('Cheap Model (GPT-5-mini)').item.json;

// Check if request was escalated
const wasEscalated = confidenceData.confidence < configData.confidence_threshold;

// Get cost rates from configuration
const cheapModelCostPer1kTokens = configData.cheap_model_cost_per_1k_tokens || 0.00015;
const expensiveModelCostPer1kTokens = configData.expensive_model_cost_per_1k_tokens || 0.005;

let modelUsed, totalTokens, costUsd, costDifferenceUsd;

if (wasEscalated) {
  // Request was escalated to expensive model
  const expensiveModelData = $('Expensive Model (GPT-5.4)').item.json;
  modelUsed = 'gpt-4o';
  totalTokens = expensiveModelData.usage?.total_tokens || 0;
  costUsd = (totalTokens / 1000) * expensiveModelCostPer1kTokens;

  // Calculate what it would have cost with cheap model
  const cheapModelTokens = cheapModelData.usage?.total_tokens || 0;
  const cheapModelCost = (cheapModelTokens / 1000) * cheapModelCostPer1kTokens;

  // Additional cost due to escalation (positive number)
  costDifferenceUsd = costUsd - cheapModelCost;
} else {
  // Request stayed with cheap model
  modelUsed = 'gpt-4o-mini';
  totalTokens = cheapModelData.usage?.total_tokens || 0;
  costUsd = (totalTokens / 1000) * cheapModelCostPer1kTokens;

  // Calculate what it would have cost with expensive model
  const expensiveModelCost = (totalTokens / 1000) * expensiveModelCostPer1kTokens;

  // Cost savings (negative number indicates savings)
  costDifferenceUsd = costUsd - expensiveModelCost;
}

// Return the result
return {
  model_used: modelUsed,
  total_tokens: totalTokens,
  cost_usd: parseFloat(costUsd.toFixed(6)),
  escalated: wasEscalated,
  cost_difference_usd: parseFloat(costDifferenceUsd.toFixed(6)),
  response: wasEscalated ? $('Expensive Model (GPT-5.4)').item.json.message?.content : cheapModelData.message?.content,
  confidence_score: confidenceData.confidence
};

